const msg = ($json.message && $json.message.text ? $json.message.text : '').trim();
const lower = msg.toLowerCase();
// ตอบเฉพาะข้อความที่เกี่ยวกับการสรุป/ผลิต/แผน/chart เท่านั้น
if (!(lower.includes('สรุป') || lower.includes('ผลิต') || lower.includes('แผน') || lower.includes('chart') || lower.includes('กราฟ'))) {
  return [];
}
const CUTOFF_HOUR = 6; // กะข้ามคืน: batch เวลา 00:00-05:59 นับเป็น "วันผลิต" ของวันก่อนหน้า
const flavorList = ["Amazon","FDS","Golden","Freshy Lychee","Freshy Strawberry","Senorita Coconut","Senorita Caramel","Freshy Blue Hawaii","Freshy Lime","Freshy Green Apple","Freshy Sala","Senorita Yuzu","MLH 02","Freshy Pineapple","Freshy Grape","Freshy Punch","Freshy blue Lemon","Senorita Fres Mint","Freshy Orange","Signature Rose","Freshy Shine Muscat Grape","Freshy Peach"];
let flavor = '';
for (const f of flavorList) { if (lower.includes(f.toLowerCase())) { flavor = f; break; } }
let date = '';
const iso = msg.match(/\d{4}-\d{2}-\d{2}/);
if (lower.includes('ทั้งหมด') || lower.includes('all')) date = '';
else if (iso) date = iso[0];
else {
  // วันผลิตปัจจุบัน: ถ้าตอนนี้ยังก่อน cutoff (เช่นตี 1) ให้ถือเป็นวันกะของเมื่อวาน
  const bkk = new Date(new Date().toLocaleString('en-US',{timeZone:'Asia/Bangkok'}));
  if (bkk.getHours() < CUTOFF_HOUR) bkk.setDate(bkk.getDate() - 1);
  date = bkk.toISOString().slice(0,10);
}
return [{ json: { text: msg, flavor, date, chatId: ($json.message && $json.message.chat ? $json.message.chat.id : '') } }];

const q = $('Parse Query').first().json;
const wantFlavor = (q.flavor || '').toLowerCase();
const actualRows = $('Read Actual').all().map(i => i.json);
let planRows = [];
try { planRows = $('Read Plan').all().map(i => i.json); } catch (e) { planRows = []; }

const CUTOFF_HOUR = 6; // กะข้ามคืน: batch ก่อน 06:00 = วันผลิตของวันก่อนหน้า
function prodDay(ts) {
  ts = String(ts || '');
  const datePart = ts.slice(0, 10);
  if (!/^\d{4}-\d{2}-\d{2}/.test(datePart)) return datePart;
  const hour = parseInt((ts.slice(11).trim().split(':')[0] || '0'), 10) || 0;
  if (hour < CUTOFF_HOUR) {
    const dt = new Date(datePart + 'T12:00:00Z');
    dt.setUTCDate(dt.getUTCDate() - 1);
    return dt.toISOString().slice(0, 10);
  }
  return datePart;
}
// คีย์เรียงตามเวลาจริง (รองรับชั่วโมงเลขเดี่ยว เช่น "0:11")
function tsKey(ts) {
  const m = String(ts || '').match(/(\d{4})-(\d{2})-(\d{2})[ T](\d{1,2}):(\d{2})(?::(\d{2}))?/);
  if (!m) return String(ts || '');
  return m[1] + m[2] + m[3] + m[4].padStart(2, '0') + m[5] + (m[6] || '00');
}
function statusEmoji(p, a) {
  if (p <= 0) return a > 0 ? '🔵' : '⚪';
  const r = a / p * 100;
  if (r >= 100) return '✅';
  if (r >= 75) return '🟢';
  if (r >= 50) return '🟡';
  return '🔴';
}

const actual = {};
const batchesByLine = {}; // "Line X | flavor" -> [{b, k}]
for (const r of actualRows) {
  const f = (r.flavor || '').toString().trim();
  if (!f) continue;
  if (q.date && prodDay(r.timestamp) !== q.date) continue;
  if (wantFlavor && !f.toLowerCase().includes(wantFlavor)) continue;
  actual[f] = (actual[f] || 0) + 1;
  const line = (r.line || '-').toString().trim();
  const b = (r.batch || '').toString().trim();
  const key = line + ' | ' + f;
  if (!batchesByLine[key]) batchesByLine[key] = [];
  if (b) batchesByLine[key].push({ b: b, k: tsKey(r.timestamp) });
}
const plan = {};
const planByLine = {}; // "Line X | flavor" -> planned batches
for (const r of planRows) {
  const f = (r.flavor || '').toString().trim();
  if (!f) continue;
  if (q.date && r.planDate && String(r.planDate) !== q.date) continue;
  if (wantFlavor && !f.toLowerCase().includes(wantFlavor)) continue;
  plan[f] = (plan[f] || 0) + Number(r.plannedBatches || 0);
  const line = (r.line || '-').toString().trim();
  const key = line + ' | ' + f;
  planByLine[key] = (planByLine[key] || 0) + Number(r.plannedBatches || 0);
}

let flavors = Array.from(new Set([...Object.keys(plan), ...Object.keys(actual)]));
if (wantFlavor) {
  const filtered = flavors.filter(f => f.toLowerCase().includes(wantFlavor));
  if (filtered.length) flavors = filtered;
}
flavors.sort();
if (flavors.length === 0) {
  return [{ json: { chatId: q.chatId, caption: '⚠️ ไม่พบข้อมูลการผลิต' + (q.date ? (' วันที่ ' + q.date) : '') + ' ครับ', chartUrl: '' } }];
}

const planData = flavors.map(f => plan[f] || 0);
const actualData = flavors.map(f => actual[f] || 0);
const chart = {
  type: 'bar',
  data: { labels: flavors, datasets: [
    { label: 'แผน', data: planData, backgroundColor: 'rgba(21,101,192,0.75)' },
    { label: 'ผลิตจริง', data: actualData, backgroundColor: 'rgba(67,160,71,0.85)' } ] },
  options: { title: { display: true, text: 'แผน vs ผลิตจริง (batch)' + (q.date ? (' ' + q.date) : '') },
    scales: { yAxes: [{ ticks: { beginAtZero: true } }] } }
};
const chartUrl = 'https://quickchart.io/chart?w=720&h=440&c=' + encodeURIComponent(JSON.stringify(chart));

const LINE = '━━━━━━━━━━━━━━━';
let cap = '📊 สรุปการผลิต   📅 ' + (q.date || 'ทั้งหมด') + '\n' + LINE + '\n';
let tp = 0, ta = 0;
for (const f of flavors) {
  const p = plan[f] || 0, a = actual[f] || 0; tp += p; ta += a;
  const pct = p > 0 ? Math.round(a / p * 100) : 0;
  cap += '\n🧃 ' + f + '\n';
  cap += '   🎯 แผน ' + p + '   ✅ จริง ' + a + '   ' + statusEmoji(p, a) + ' ' + pct + '%\n';
}
cap += LINE + '\n📦 รวม:  ✅ ' + ta + ' / 🎯 ' + tp + ' batch';

// รายละเอียดต่อ Line: แผน + batch ที่ผลิตจริง (เรียงตามเวลาผลิต)
const allKeys = Array.from(new Set([...Object.keys(planByLine), ...Object.keys(batchesByLine)])).sort();
if (allKeys.length) {
  cap += '\n\n🏭 รายละเอียดแต่ละไลน์';
  for (const k of allKeys) {
    const parts = k.split(' | ');
    const lineName = parts[0], fl = parts[1] || '';
    const planN = planByLine[k] || 0;
    const list = (batchesByLine[k] || []).slice()
      .sort((x, y) => x.k < y.k ? -1 : x.k > y.k ? 1 : 0)
      .map(o => o.b);
    cap += '\n\n▸ ' + lineName + ' · 🧃 ' + fl;
    cap += '\n   🎯 แผน ' + planN + '   ✅ จริง ' + list.length;
    if (list.length) cap += '\n   🔖 Batch: ' + list.join(', ');
  }
}
return [{ json: { chatId: q.chatId, chartUrl, caption: cap } }];
